// =========================================
// PREPARE DATA – BRANDED TRACKING ONLY (CLEAN + SIMPLE)
// =========================================

// Extract user message + history safely
const userMessage =
  $input.item.json.body?.message ||
  $input.item.json.message ||
  "";

const conversationHistory =
  $input.item.json.body?.conversationHistory ||
  $input.item.json.conversationHistory ||
  [];

const previousData =
  $input.item.json.body?.onboardingData ||
  $input.item.json.onboardingData ||
  {};

const chatID = `chat-${Date.now()}`;

// =========================================
// SYSTEM PROMPT BASE
// =========================================

let systemPrompt = `You are a friendly Tradedoubler onboarding assistant.

PERSONALITY:
- Warm, polite, and professional
- Ask ONE question at a time
- Keep responses short unless delivering the branded tracking intro
- Assume the advertiser knows NOTHING technical

STRICT RULES:
- FIRST: Ask for name
- THEN: Ask for company
- THEN: Send the full branded tracking introduction ONCE
- The branded intro MUST begin with "Hi <Name>!"
- The branded intro MUST include the request for their website URL
- NEVER detect or mention any domain before the branded intro is sent
- After user provides website → ALWAYS generate:
      visit.<domain>
      statics.<domain>
- ALWAYS lowercase domain
- NEVER ask “do these look correct”
- ALWAYS say the domains have been passed to the Tech Team
- STOP after sending the branded domains; no further onboarding steps

CONTEXT:
Name: ${previousData.clientName || "Unknown"}
Company: ${previousData.companyName || "Unknown"}
`;


// =========================================
// STAGE SELECTION
// =========================================

let currentStage = "ask_name";

if (previousData.clientName && !previousData.companyName) {
  currentStage = "ask_company";
}
else if (previousData.clientName && previousData.companyName && !previousData.brandedIntroSentExplicitly) {
  currentStage = "branded_intro";
}
else if (previousData.brandedIntroSentExplicitly && !previousData.rootDomain) {
  currentStage = "await_domain";
}
else if (previousData.rootDomain && !previousData.subdomainsGenerated) {
  currentStage = "generate_subdomains";
}


// =========================================
// STAGE OUTPUT
// =========================================

// 1️⃣ ASK NAME
if (currentStage === "ask_name") {
  systemPrompt += `
Ask: "Hi! I'm here to help you get your Tradedoubler tracking set up. What's your name?"
WAIT.
`;
}

// 2️⃣ ASK COMPANY
else if (currentStage === "ask_company") {
  systemPrompt += `
Ask: "Nice to meet you, ${previousData.clientName}! Which company are you with?"
WAIT.
`;
}

// 3️⃣ SEND FULL BRANDED TRACKING INTRO
else if (currentStage === "branded_intro") {
  systemPrompt += `
Say EXACTLY:

"Hi ${previousData.clientName}!

As part of the onboarding process there's a few technical elements that need to be finalised before we can launch the programs across the Tradedoubler Network.

Branded Tracking

To combat the increasing challenges of Browser Privacy settings and Adblockers on tracking technology, Tradedoubler has launched Branded Tracking. This solution will mask Tradedoubler tracking scripts under your own domain, preventing them from being disrupted. Branded Tracking also comes with the added benefit of masking publisher click links under your domain as well, creating a more positive user journey for consumers.

To set this up, we will need two new subdomains — one for ad serving and one for tracking. You don’t need to configure the subdomains on your end; we only require your website domain so we can generate the correct branded domains. Once these domains are registered in our system, our Technical Team will configure them and provide you with the DNS values needed to establish the connection.

Please could you provide me with the URL to your website?"

Mark: brandedIntroSentExplicitly = true
STOP.
`;
}

// 4️⃣ WAIT FOR DOMAIN
else if (currentStage === "await_domain") {
  systemPrompt += `
User should now send their website URL.
WAIT.
`;
}

// 5️⃣ GENERATE SUBDOMAINS + HANDOFF
else if (currentStage === "generate_subdomains") {
  const domain = previousData.rootDomain.toLowerCase();

  systemPrompt += `
Say EXACTLY:

"Great, thanks! Based on ${domain}, here are your branded tracking domains:

• visit.${domain}
• statics.${domain}

These have now been passed to our Technical Team to configure. Once everything is integrated into our system, I'll share the DNS values you’ll need to add on your end."

Mark: subdomainsGenerated = true
STOP.
`;
}


// =========================================
// BUILD MESSAGE ARRAY
// =========================================

const messages = [{ role: "system", content: systemPrompt }];

conversationHistory.forEach(m =>
  messages.push({
    role: m.role === "user" ? "user" : "assistant",
    content: m.content
  })
);

messages.push({ role: "user", content: userMessage });


// =========================================
// RETURN OUTPUT
// =========================================

return [{
  json: {
    messages,
    onboardingData: { ...previousData, currentStage },
    sessionInfo: { chatID }
  }
}];

// ========================================
// PROCESS DATA – BRANDED TRACKING ONLY (CLEAN + STABLE)
// ========================================

const input = $input.item.json;

// Extract AI response safely
const aiResponse =
  input.output ||
  input.text ||
  input.response ||
  JSON.stringify(input);

// Load previous onboarding state
const previousData = input.onboardingData || {};
const messages = input.messages || [];

const lastUserMessage = messages.filter(m => m.role === "user").pop();
const userMessage = (lastUserMessage?.content || "").trim();
const lower = userMessage.toLowerCase();

let data = { ...previousData };


// ========================================
// 1. CAPTURE NAME (Flexible)
// ========================================
if (!data.clientName) {
  const match = userMessage.match(/\b(?:i am|i'm|my name is|this is)\s+([A-Za-z]+)/i);
  if (match) {
    const raw = match[1];
    data.clientName = raw.charAt(0).toUpperCase() + raw.slice(1).toLowerCase();
  }
}


// ========================================
// 2. CAPTURE COMPANY (Flexible)
// ========================================
if (data.clientName && !data.companyName) {
  const companyMatch = userMessage.match(/\b(?:work at|from|with|representing)\s+([A-Za-z0-9&\s]+)/i);
  if (companyMatch) {
    data.companyName = companyMatch[1].trim();
  }
}


// ========================================
// 3. DETECT BRANDED INTRO SENT
// ========================================
if (
  aiResponse.includes("As part of the onboarding process") &&
  aiResponse.includes("Branded Tracking") &&
  aiResponse.includes("provide me with the URL to your website")
) {
  data.brandedIntroSentExplicitly = true;
}


// ========================================
// 4. CAPTURE DOMAIN ONLY AFTER BRANDED INTRO
// ========================================
if (data.brandedIntroSentExplicitly && !data.rootDomain) {
  const dm = lower.match(/([a-z0-9][a-z0-9-]{0,61}[a-z0-9]\.[a-z]{2,}(?:\.[a-z]{2,})?)/);
  if (dm) {
    const clean = dm[0].replace(/^(https?:\/\/)?(www\.)?/, "");
    data.rootDomain = clean;
    data.visitSubdomain = `visit.${clean}`;
    data.staticsSubdomain = `statics.${clean}`;
    data.subdomainsGenerated = true;
  }
}


// ========================================
// 5. DETECT TECH TEAM HANDOFF
// ========================================
if (data.subdomainsGenerated && !data.techTeamNotified) {
  const resp = aiResponse.toLowerCase();
  if (
    resp.includes("passed these to our technical team") ||
    resp.includes("passed these to our tech team") ||
    resp.includes("i've passed these")
  ) {
    data.techTeamNotified = true;
  }
}


// ========================================
// PROGRESS SUMMARY
// ========================================
const progress = {
  hasName: !!data.clientName,
  hasCompany: !!data.companyName,
  brandedIntroSentExplicitly: !!data.brandedIntroSentExplicitly,
  hasDomain: !!data.rootDomain,
  subdomainsGenerated: !!data.subdomainsGenerated,
  techTeamNotified: !!data.techTeamNotified
};

const completed = Object.values(progress).filter(Boolean).length;
const total = Object.keys(progress).length;


// ========================================
// RETURN CLEAN OUTPUT (SAFE CHATID HANDLING)
// ========================================
return {
  response: aiResponse,
  onboardingData: data,
  progress,
  completed,
  total,
  percentage: Math.round((completed / total) * 100),
  chatID: input.sessionInfo?.chatID || previousData.sessionInfo?.chatID || ""
};

// ========================================
// SIMPLE VALIDATION GATE – BRANDED ONLY
// ========================================

const input = $input.item.json;
let result = { ...input };

// Extract last user message
const messages = input.messages || [];
const lastUserMessage = messages.filter(m => m.role === "user").pop();
const userMessage = (lastUserMessage?.content || "").trim();

// OPTIONAL: Light domain warning (non-blocking)
const domainMatch = userMessage.match(/([a-z0-9][a-z0-9-]{0,61}[a-z0-9]\.[a-z]{2,}(?:\.[a-z]{2,})?)/i);

if (domainMatch) {
  const cleaned = domainMatch[0].replace(/^(https?:\/\/)?(www\.)?/, "");
  const regex = /^[a-z0-9][a-z0-9\-]{0,61}[a-z0-9]\.[a-z]{2,}(?:\.[a-z]{2,})?$/i;
  if (!regex.test(cleaned)) {
    result.validationWarning = "The domain format looks unusual, please double-check.";
  }
}

result.validationPassed = true;
return result;

// Format Response for Webhook

const processedData = $input.item.json;

let response = processedData.response;
if (typeof response !== 'string') {
  response = JSON.stringify(response);
}

return {
  response: response,
  onboardingData: processedData.onboardingData || {},
  checklist: processedData.checklist || {},
  isComplete: processedData.isComplete || false,
  completionPercentage: processedData.completionPercentage || 0
};
